func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

population.algorithm:
Greedy insertion with normalized marginal cost scoring using time-window slack penalty factor α=0.5 and distance‑ratio factor β=0.3 to prioritize feasible and compact routes, trying each existing assign plus a potential new assign, falling back to first feasible existing or new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 0.5 // time‑window slack penalty weight
	const beta = 0.3  // distance ratio bonus/penalty weight
	orderCount := len(oris)
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		id := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]
		bestScore := 1e100
		bestAssignIdx := -1
		bestSaved := Assign{}
		commitToNewEmpty := false
		currentAssigns := dispatch.AssignsLen
		for idx := 0; idx <= currentAssigns; idx++ {
			isNew := idx == currentAssigns
			var assignPtr *Assign
			if isNew {
				if currentAssigns >= MAXASSIGNS {
					continue
				}
				assignPtr = &dispatch.Assigns[idx]
			} else {
				assignPtr = &dispatch.Assigns[idx]
			}
			savedState := *assignPtr
			if assignPtr.AddShip(id, ori, des) {
				assignPtr.GenRoute()
				newCost := assignPtr.Cost
				ok := newCost >= 0
				if ok {
					var baseline float64
					if isNew {
						baseline = 0.0
					} else {
						baseline = savedState.Cost
					}
					marginal := newCost - baseline
					timePenalty := 0.0
					routeLen := 0.0
					if isNew {
						routeLen = cal_dis(ori, des)
					} else {
						routeLen = cal_dis(savedState.StationCurrent, ori) +
							cal_dis(ori, des) +
							cal_dis(des, savedState.StationCurrent)
					}
					if routeLen > 0 {
						directDist := cal_dis(ori, des)
						distRatio := routeLen / directDist
						if distRatio > 1.001 {
							timePenalty += beta * (distRatio - 1.0)
						} else {
							timePenalty -= beta * (1.0 - distRatio)
						}
					}
					score := marginal*(1.0+alpha*timePenalty)
					if score < bestScore {
						bestScore = score
						bestAssignIdx = idx
						bestSaved = savedState
						commitToNewEmpty = isNew
					}
				}
			}
			*assignPtr = savedState
			assignPtr.GenRoute()
		}
		if bestAssignIdx >= 0 {
			var target *Assign
			if commitToNewEmpty {
				target = &dispatch.Assigns[bestAssignIdx]
				_ = target.AddShip(id, ori, des)
				target.GenRoute()
				if target.Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					*target = bestSaved
					target.GenRoute()
					commitToNewEmpty = false
				}
			} else {
				target = &dispatch.Assigns[bestAssignIdx]
				*target = bestSaved
				target.GenRoute()
				_ = target.AddShip(id, ori, des)
				target.GenRoute()
			}
		}
		wasInserted := false
		for checkIdx := 0; checkIdx < dispatch.AssignsLen; checkIdx++ {
			checkAssign := &dispatch.Assigns[checkIdx]
			tmpSave := *checkAssign
			if checkAssign.AddShip(id, ori, des) {
				checkAssign.GenRoute()
				if checkAssign.Cost >= 0 {
					wasInserted = true
					break
				} else {
					*checkAssign = tmpSave
					checkAssign.GenRoute()
				}
			}
		}
		if !wasInserted && dispatch.AssignsLen < MAXASSIGNS {
			newSlot := &dispatch.Assigns[dispatch.AssignsLen]
			tmpSave := *newSlot
			if newSlot.AddShip(id, ori, des) {
				newSlot.GenRoute()
				if newSlot.Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					*newSlot = tmpSave
					newSlot.GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

