Evaluate insertion cost for each order into existing assigns via trial-and-error, selecting minimal marginal cost increase, falling back to new assign creation if necessary.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignIndices := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		assignIndices = append(assignIndices, i)
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIndex := -1
		bestCostDelta := 0.0
		fallbackCreated := false

		id := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		shuffledIndices := make([]int, len(assignIndices))
		copy(shuffledIndices, assignIndices)

		for attempt := 0; attempt < len(shuffledIndices)+1; attempt++ {
			currentIdx := -1
			if attempt < len(shuffledIndices) {
				currentIdx = shuffledIndices[attempt]
			} else {
				if bestAssignIndex != -1 || fallbackCreated {
					continue
				}
				if dispatch.AssignsLen >= MAXASSIGNS {
					currentIdx = 0
				} else {
					currentIdx = dispatch.AssignsLen
					fallbackCreated = true
				}
			}

			if currentIdx < 0 || currentIdx >= MAXASSIGNS {
				continue
			}

			oldStateValid := false
			var oldCost float64
			if dispatch.Assigns[currentIdx].Cost >= 0 {
				oldCost = dispatch.Assigns[currentIdx].Cost
				oldStateValid = true
			}

			addSuccess := dispatch.Assigns[currentIdx].AddShip(id, ori, des)
			if addSuccess {
				dispatch.Assigns[currentIdx].GenRoute()
				newCost := dispatch.Assigns[currentIdx].Cost
				if newCost >= 0 {
					costDelta := 0.0
					if oldStateValid {
						costDelta = newCost - oldCost
					} else {
						costDelta = newCost
					}

					if bestAssignIndex == -1 || costDelta < bestCostDelta {
						bestAssignIndex = currentIdx
						bestCostDelta = costDelta
					}

					dispatch.Assigns[currentIdx].RemoveShip(id)
					if oldStateValid {
						dispatch.Assigns[currentIdx].Cost = oldCost
					}
				} else {
					dispatch.Assigns[currentIdx].RemoveShip(id)
				}
			}
		}

		insertSucceeded := false
		targetIdx := bestAssignIndex
		if targetIdx == -1 && fallbackCreated {
			targetIdx = dispatch.AssignsLen
		}

		if targetIdx >= 0 && targetIdx < MAXASSIGNS {
			if dispatch.Assigns[targetIdx].AddShip(id, ori, des) {
				dispatch.Assigns[targetIdx].GenRoute()
				insertSucceeded = true
				if targetIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		}

		if !insertSucceeded {
			if dispatch.AssignsLen < MAXASSIGNS {
				if dispatch.Assigns[dispatch.AssignsLen].AddShip(id, ori, des) {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					dispatch.AssignsLen++
					insertSucceeded = true
				}
			}
		}

		if !insertSucceeded && dispatch.AssignsLen > 0 {
			if dispatch.Assigns[0].AddShip(id, ori, des) {
				dispatch.Assigns[0].GenRoute()
				insertSucceeded = true
			}
		}

		if insertSucceeded {
			assignIndices = make([]int, 0, dispatch.AssignsLen)
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].Cost >= 0 {
					assignIndices = append(assignIndices, i)
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

