				dispatch.Assigns[potentialNewIdx].GenRoute()
				newCost := dispatch.Assigns[potentialNewIdx].Cost
				if newCost >= 0 {
					costDelta := newCost - oldCost
					if costDelta < bestTrial.costDelta {
						bestTrial.idx = potentialNewIdx
						bestTrial.costDelta = costDelta
						bestTrial.ok = true
					}
				}
				dispatch.Assigns[potentialNewIdx].RemoveShip(shipID)
				dispatch.Assigns[potentialNewIdx].GenRoute()
			}
		}

		if bestTrial.ok {
			chosenIdx := bestTrial.idx
			if chosenIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = chosenIdx + 1
			}
			dispatch.Assigns[chosenIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[chosenIdx].GenRoute()
		} else {
			inserted := false
			for i := 0; i < MAXASSIGNS && !inserted; i++ {
				if dispatch.Assigns[i].AddShip(shipID, ori, des) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						if i >= dispatch.AssignsLen {
							dispatch.AssignsLen = i + 1
						}
						inserted = true
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
			if !inserted {
				if potentialNewIdx < MAXASSIGNS {
					dispatch.Assigns[potentialNewIdx].AddShip(shipID, ori, des)
					dispatch.Assigns[potentialNewIdx].GenRoute()
					dispatch.AssignsLen = potentialNewIdx + 1
				} else {
					for i := 0; i < MAXASSIGNS; i++ {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
					dispatch.Assigns[0].AddShip(shipID, ori, des)
					dispatch.Assigns[0].GenRoute()
					if dispatch.AssignsLen == 0 {
						dispatch.AssignsLen = 1
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

