Greedy insertion with cheapest‑cost evaluation across all routes, including empty ones, using a two‑phase try‑all and fallback‑to‑new‑assign strategy.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	// Phase 1: Try inserting each order into the best existing assign (including empty assigns within current length)
	for jj := 0; jj < orderCount; jj++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		foundFeasible := false

		// Evaluate every existing assign slot (both non-empty and empty ones already counted in AssignsLen)
		for idx := 0; idx < MAXASSIGNS; idx++ {
			// Skip slots beyond current length that we don't want to consider yet (we'll use them as fallback later)
			if idx >= MAXASSIGNS {
				continue
			}
			// Only consider assigns up to current AssignsLen plus one potential new slot at AssignsLen
			if idx > dispatch.AssignsLen {
				break
			}

			// Save current state of this assign
			savedCost := dispatch.Assigns[idx].Cost
			// We'll rely on AddShip/RemoveShip/GenRoute to maintain consistency; no deep copy needed here.

			ok := dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					costDelta := newCost - savedCost
					if !foundFeasible || costDelta < bestCostDelta {
						foundFeasible = true
						bestCostDelta = costDelta
						bestAssignIdx = idx
					}
				}
			}
			// Undo the trial insertion
			dispatch.Assigns[idx].RemoveShip(total_ship + jj)
			dispatch.Assigns[idx].GenRoute()
			// Restore original cost (though GenRoute should have restored it)
			dispatch.Assigns[idx].Cost = savedCost
		}

		if foundFeasible {
			// Commit to the best assign found
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			// If bestAssignIdx was equal to dispatch.AssignsLen, it means we used a fresh empty slot -> extend length
			if bestAssignIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		} else {
			// Fallback: create a new assign at the end (if within limit)
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx >= MAXASSIGNS {
				// No more assign slots available — this should not happen under normal constraints,
				// but we must still attempt insertion somewhere. We try every slot again without saving/restoring,
				// because we must place the order. This is a last-resort forced insertion.
				insertedFallback := false
				for idx := 0; idx < dispatch.AssignsLen; idx++ {
					if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
						dispatch.Assigns[idx].GenRoute()
						insertedFallback = true
						break
					}
				}
				if !insertedFallback && dispatch.AssignsLen < MAXASSIGNS {
					dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+jj, oris[jj], dess[jj])
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					dispatch.AssignsLen++
				}
			} else {
				dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

