Evaluate all feasible insertion positions across existing and new assigns using a greedy best-cost strategy with fallback creation.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := range oris {
		bestAssignIdx := -1
		bestDeltaCost := 1e308
		orderID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		// Try inserting into each existing assign
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			savedState := assign.Cost
			if assign.AddShip(orderID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - savedState
				if newCost >= 0 && costDelta < bestDeltaCost {
					bestDeltaCost = costDelta
					bestAssignIdx = i
				}
				assign.RemoveShip(orderID)
				assign.GenRoute()
			}
		}

		// Try inserting into a potential new assign
		if dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
			assign := &dispatch.Assigns[i]
			savedState := assign.Cost
			if assign.AddShip(orderID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - savedState
				if newCost >= 0 && costDelta < bestDeltaCost {
					bestDeltaCost = costDelta
					bestAssignIdx = i
				}
				assign.RemoveShip(orderID)
				assign.GenRoute()
			}
		}

		// Commit the best insertion found
		if bestAssignIdx >= 0 {
			targetAssign := &dispatch.Assigns[bestAssignIdx]
			success := targetAssign.AddShip(orderID, ori, des)
			if success {
				targetAssign.GenRoute()
				if bestAssignIdx == dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			} else {
				// Fallback: create new assign if within limit
				if dispatch.AssignsLen < MAXASSIGNS {
					newAssign := &dispatch.Assigns[dispatch.AssignsLen]
					newAssign.AddShip(orderID, ori, des)
					newAssign.GenRoute()
					dispatch.AssignsLen++
				}
			}
		} else {
			// No feasible insertion found among tries; fallback to safe seed insertion
			inserted := false
			for i := 0; i < dispatch.AssignsLen && !inserted; i++ {
				if dispatch.Assigns[i].AddShip(orderID, ori, des) {
					dispatch.Assigns[i].GenRoute()
					inserted = true
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				newAssign := &dispatch.Assigns[dispatch.AssignsLen]
				newAssign.AddShip(orderID, ori, des)
				newAssign.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

